package main

import (
	"fmt"
	"strings"
)

func main() {
	message := "Hello, Go World!"

	// Convert case
	fmt.Println(strings.ToUpper(message))  // HELLO, GO WORLD!
	fmt.Println(strings.ToLower(message))  // hello, go world!

	// Check contents
	fmt.Println(strings.Contains(message, "Go"))     // true
	fmt.Println(strings.HasPrefix(message, "Hello")) // true
	fmt.Println(strings.HasSuffix(message, "World!"))// true

	// Replace
	newMsg := strings.Replace(message, "Go", "Gopher", 1)
	fmt.Println(newMsg)  // Hello, Gopher World!

	// Split
	words := strings.Split(message, " ")
	fmt.Println(words)  // [Hello, Go World!]

	// Count
	fmt.Println(strings.Count(message, "o"))  // 2
}

