package main

import "fmt"

// Without iota (tedious and error-prone)
// const (
//     Sunday    = 0
//     Monday    = 1
//     Tuesday   = 2
//     ...etc
// )

// With iota (elegant!)
const (
	Sunday    = iota  // 0
	Monday            // 1 (iota auto-increments)
	Tuesday           // 2
	Wednesday         // 3
	Thursday          // 4
	Friday            // 5
	Saturday          // 6
)

// iota resets in each const block
const (
	Small  = iota  // 0
	Medium         // 1
	Large          // 2
)

func main() {
	fmt.Println("Wednesday =", Wednesday)  // 3
	fmt.Println("Large =", Large)           // 2
}

package main

import "fmt"

// Skip the zero value
const (
	_         = iota  // 0 (assigned to blank identifier, discarded)
	January          // 1
	February         // 2
	March            // 3
)

// Multiply iota
const (
	KB = 1024 * (iota + 1)  // 1024
	MB                       // 2048... wait, that's wrong!
)

// Correct way: use bit shifting
const (
	_  = iota
	KB2 = 1 << (10 * iota)  // 1 << 10 = 1024
	MB2                      // 1 << 20 = 1048576
	GB2                      // 1 << 30 = 1073741824
)

func main() {
	fmt.Println("January:", January)   // 1
	fmt.Println("KB:", KB2)             // 1024
	fmt.Println("MB:", MB2)             // 1048576
	fmt.Println("GB:", GB2)             // 1073741824
}

package main

import (
	"fmt"
	"strconv"
)

func main() {
	// String to Integer
	numStr := "42"
	num, err := strconv.Atoi(numStr)  // Atoi = "ASCII to Integer"
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Println("Number:", num)       // 42
		fmt.Println("Doubled:", num * 2)  // 84
	}

	// Integer to String
	age := 25
	ageStr := strconv.Itoa(age)  // Itoa = "Integer to ASCII"
	fmt.Println("I am " + ageStr + " years old")

	// String to Float
	piStr := "3.14159"
	pi, err := strconv.ParseFloat(piStr, 64)  // 64 = float64
	if err == nil {
		fmt.Println("Pi:", pi)
	}
}

