sections.code:
package main

import "fmt"

func main() {
	// Form 1: Classic for (like C/Java)
	// for init; condition; post { }
	fmt.Println("=== Classic For ===")
	for i := 0; i < 5; i++ {
		fmt.Println("Count:", i)
	}
	// Output: 0, 1, 2, 3, 4

	// Form 2: While-style (condition only)
	fmt.Println("\n=== While-Style ===")
	counter := 10
	for counter > 0 {
		fmt.Println("Countdown:", counter)
		counter -= 2
	}
	// Output: 10, 8, 6, 4, 2

	// Form 3: Infinite loop (no condition)
	fmt.Println("\n=== Infinite with Break ===")
	num := 1
	for {
		if num > 3 {
			break  // Exit the loop!
		}
		fmt.Println("Num:", num)
		num++
	}
}

package main

import "fmt"

func main() {
	// break: Exit the loop immediately
	for i := 0; i < 10; i++ {
		if i == 5 {
			fmt.Println("Found 5! Stopping.")
			break
		}
		fmt.Println(i)
	}
	// Output: 0, 1, 2, 3, 4, Found 5! Stopping.

	fmt.Println("---")

	// continue: Skip the rest of THIS iteration
	for i := 0; i < 10; i++ {
		if i % 2 == 0 {
			continue  // Skip even numbers
		}
		fmt.Println(i)  // Only prints odd numbers
	}
	// Output: 1, 3, 5, 7, 9
}

