package main

import "fmt"

func main() {
	// The Accumulator Pattern: build up a result over iterations

	// Calculate factorial of 5 (5! = 5 × 4 × 3 × 2 × 1)
	n := 5
	factorial := 1
	for i := 1; i <= n; i++ {
		factorial *= i  // factorial = factorial * i
	}
	fmt.Printf("%d! = %d\n", n, factorial)  // 5! = 120

	// Build a string
	result := ""
	for i := 0; i < 5; i++ {
		result += "⭐"
	}
	fmt.Println(result)  // ⭐⭐⭐⭐⭐
}

