package main

import "fmt"

// Calculate BMI: weight(kg) / height(m)^2
func calculateBMI(weightKg, heightM float64) float64 {
	return weightKg / (heightM * heightM)
}

// Categorize BMI
func bmiCategory(bmi float64) string {
	switch {
	case bmi < 18.5:
		return "Underweight"
	case bmi < 25:
		return "Normal"
	case bmi < 30:
		return "Overweight"
	default:
		return "Obese"
	}
}

func main() {
	bmi := calculateBMI(70, 1.75)
	category := bmiCategory(bmi)
	fmt.Printf("BMI: %.1f (%s)\n", bmi, category)
}

