package main

import "fmt"

func main() {
	// Anonymous function (no name) — called immediately
	func() {
		fmt.Println("I'm anonymous!")
	}()

	// Anonymous function stored in a variable
	add := func(a, b int) int {
		return a + b
	}
	fmt.Println(add(3, 4))  // 7

	// Closure: function that "remembers" variables from its surrounding scope
	counter := 0
	increment := func() int {
		counter++  // Accesses 'counter' from the outer scope
		return counter
	}

	fmt.Println(increment())  // 1
	fmt.Println(increment())  // 2
	fmt.Println(increment())  // 3
	fmt.Println("Counter:", counter)  // 3
}

