package main

import "fmt"

func main() {
    days := [7]string{"Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"}

    // Access by index (starts at 0!)
    fmt.Println(days[0]) // Mon
    fmt.Println(days[4]) // Fri
