// Returns the min AND max from a slice
func minMax(numbers []int) (int, int) {
    min := numbers[0]
    max := numbers[0]

    for _, n := range numbers[1:] {
        if n < min {
            min = n
        }
        if n > max {
            max = n
        }
    }
    return min, max
}

func main() {
