package main

import (
    "fmt"
    "math"
    "sort"
)

func analyzeScores(scores ...int) (mean float64, median float64, min int, max int) {
    if len(scores) == 0 {
        return 0, 0, 0, 0
    }

    // Calculate mean
    total := 0
    for _, s := range scores {
        total += s
    }
    mean = float64(total) / float64(len(scores))

    // Calculate median (middle value when sorted)
    sorted := append([]int{}, scores...) // safe copy
    sort.Ints(sorted)
    mid := len(sorted) / 2
    if len(sorted)%2 == 0 {
        median = float64(sorted[mid-1]+sorted[mid]) / 2.0
    } else {
        median = float64(sorted[mid])
    }

    min = sorted[0]
    max = sorted[len(sorted)-1]

    mean = math.Round(mean*100) / 100 // round to 2 decimal places
    return
}

func main() {
    avg, med, lo, hi := analyzeScores(85, 92, 78, 95, 88, 72, 91)
    fmt.Printf("Mean: %.2f, Median: %.2f, Min: %d, Max: %d\n", avg, med, lo, hi)
    // Mean: 85.86, Median: 88.00, Min: 72, Max: 95
}

