package main

import (
    "fmt"
    "sort"
    "strings"
)

// Store each student's grades
var gradeBook = map[string][]int{
    "Alice":   {92, 88, 95, 78, 91},
    "Bob":     {75, 82, 68, 90, 73},
    "Charlie": {98, 95, 100, 92, 97},
    "Diana":   {55, 62, 48, 71, 59},
    "Eve":     {85, 88, 91, 87, 83},
}

// Calculate average for one student
func average(grades []int) float64 {
    total := 0
    for _, g := range grades {
        total += g
    }
    return float64(total) / float64(len(grades))
}

// Convert numeric average to letter grade
func letterGrade(avg float64) string {
    switch {
    case avg >= 90:
        return "A"
    case avg >= 80:
        return "B"
    case avg >= 70:
        return "C"
    case avg >= 60:
        return "D"
    default:
        return "F"
    }
}

// Get students who are struggling (avg < 70)
func findStruggling(book map[string][]int) []string {
    var struggling []string
    for name, grades := range book {
        if average(grades) < 70 {
            struggling = append(struggling, name)
        }
    }
    sort.Strings(struggling)
    return struggling
}

// Get the class honor roll (avg >= 90)
func honorRoll(book map[string][]int) []string {
    var honors []string
    for name, grades := range book {
        if average(grades) >= 90 {
            honors = append(honors, name)
        }
    }
    sort.Strings(honors)
    return honors
}

// Generate a full report
func generateReport(book map[string][]int) {
    fmt.Println(strings.Repeat("=", 50))
    fmt.Println("        STUDENT GRADE REPORT")
    fmt.Println(strings.Repeat("=", 50))

    // Collect all names and sort them
    names := make([]string, 0, len(book))
    for name := range book {
        names = append(names, name)
    }
    sort.Strings(names)

    // Print each student's report
    for _, name := range names {
        grades := book[name]
        avg := average(grades)
        letter := letterGrade(avg)
        fmt.Printf("%-10s | Avg: %5.1f | Grade: %s | Grades: %v\n",
            name, avg, letter, grades)
    }

    fmt.Println(strings.Repeat("-", 50))

    // Honor roll
    honors := honorRoll(book)
    fmt.Printf("Honor Roll: %s\n", strings.Join(honors, ", "))

    // Struggling students
    struggling := findStruggling(book)
    if len(struggling) > 0 {
        fmt.Printf("Need Help:  %s\n", strings.Join(struggling, ", "))
    }

    fmt.Println(strings.Repeat("=", 50))
}

func main() {
    generateReport(gradeBook)
}

