package main

import "fmt"

type Rectangle struct {
    Width  float64
    Height float64
}

// Method with a VALUE receiver
func (r Rectangle) Area() float64 {
    return r.Width * r.Height
}

func (r Rectangle) Perimeter() float64 {
    return 2 * (r.Width + r.Height)
}

func (r Rectangle) String() string {
    return fmt.Sprintf("Rectangle(%.1f × %.1f)", r.Width, r.Height)
}

func main() {
    rect := Rectangle{Width: 10, Height: 5}

    fmt.Println(rect.Area())      // 50
    fmt.Println(rect.Perimeter()) // 30
    fmt.Println(rect.String())    // Rectangle(10.0 × 5.0)
}

package main

import "fmt"

type BankAccount struct {
    Owner   string
    Balance float64
}

// Value receiver — cannot modify the original
func (a BankAccount) DisplayBalance() string {
    return fmt.Sprintf("%s's balance: $%.2f", a.Owner, a.Balance)
}

// Pointer receiver — CAN modify the original
func (a *BankAccount) Deposit(amount float64) {
    a.Balance += amount
}

func (a *BankAccount) Withdraw(amount float64) bool {
    if amount > a.Balance {
        fmt.Println("Insufficient funds!")
        return false
    }
    a.Balance -= amount
    return true
}

func main() {
    account := BankAccount{Owner: "Alice", Balance: 1000.00}
    fmt.Println(account.DisplayBalance()) // Alice's balance: $1000.00

    account.Deposit(500.00)
    fmt.Println(account.DisplayBalance()) // Alice's balance: $1500.00

    account.Withdraw(200.00)
    fmt.Println(account.DisplayBalance()) // Alice's balance: $1300.00

    account.Withdraw(5000.00) // Insufficient funds!
}

