package main

import "fmt"

type Stats struct {
    Health    int
    MaxHealth int
    Strength  int
    Defense   int
}

func (s *Stats) TakeDamage(damage int) {
    actual := damage - s.Defense
    if actual < 0 {
        actual = 0
    }
    s.Health -= actual
    if s.Health < 0 {
        s.Health = 0
    }
}

func (s *Stats) IsAlive() bool {
    return s.Health > 0
}

type Warrior struct {
    Name  string
    Stats // embedded
    Rage  int
}

type Mage struct {
    Name  string
    Stats // embedded — same Stats, different character!
    Mana  int
}

func main() {
    warrior := Warrior{
        Name:  "Thorin",
        Stats: Stats{Health: 100, MaxHealth: 100, Strength: 15, Defense: 8},
        Rage:  0,
    }

    mage := Mage{
        Name:  "Gandalf",
        Stats: Stats{Health: 60, MaxHealth: 60, Strength: 5, Defense: 3},
        Mana:  100,
    }

    // Both can use Stats methods!
    warrior.TakeDamage(20) // Actual: 20-8=12
    mage.TakeDamage(10)    // Actual: 10-3=7

    fmt.Printf("%s: HP %d/%d (alive: %v)\n", warrior.Name, warrior.Health, warrior.MaxHealth, warrior.IsAlive())
    fmt.Printf("%s: HP %d/%d (alive: %v)\n", mage.Name, mage.Health, mage.MaxHealth, mage.IsAlive())
