package main

import (
    "fmt"
    "strings"
    "time"
)

// Priority levels
const (
    PriorityLow    = "LOW"
    PriorityMedium = "MEDIUM"
    PriorityHigh   = "HIGH"
)

type Task struct {
    ID          int
    Title       string
    Description string
    Priority    string
    Completed   bool
    CreatedAt   time.Time
    CompletedAt time.Time
}

func (t Task) String() string {
    status := "[ ]"
    if t.Completed {
        status = "[✓]"
    }
    return fmt.Sprintf("%s #%d [%s] %s", status, t.ID, t.Priority, t.Title)
}

type TaskManager struct {
    tasks  []Task
    nextID int
}

func NewTaskManager() *TaskManager {
    return &TaskManager{nextID: 1}
}

func (tm *TaskManager) Add(title, description, priority string) Task {
    task := Task{
        ID:          tm.nextID,
        Title:       title,
        Description: description,
        Priority:    priority,
        CreatedAt:   time.Now(),
    }
    tm.tasks = append(tm.tasks, task)
    tm.nextID++
    return task
}

func (tm *TaskManager) Complete(id int) bool {
    for i := range tm.tasks {
        if tm.tasks[i].ID == id {
            tm.tasks[i].Completed = true
            tm.tasks[i].CompletedAt = time.Now()
            return true
        }
    }
    return false
}

func (tm *TaskManager) Delete(id int) bool {
    for i, task := range tm.tasks {
        if task.ID == id {
            tm.tasks = append(tm.tasks[:i], tm.tasks[i+1:]...)
            return true
        }
    }
    return false
}

func (tm *TaskManager) ListAll() {
    if len(tm.tasks) == 0 {
        fmt.Println("No tasks yet!")
        return
    }
    for _, task := range tm.tasks {
        fmt.Println(task)
    }
}

func (tm *TaskManager) ListByPriority(priority string) []Task {
    var result []Task
    for _, task := range tm.tasks {
        if task.Priority == priority {
            result = append(result, task)
        }
    }
    return result
}

func (tm *TaskManager) Stats() (total, completed, pending int) {
    total = len(tm.tasks)
    for _, task := range tm.tasks {
        if task.Completed {
            completed++
        }
    }
    pending = total - completed
    return
}

func main() {
    tm := NewTaskManager()

    // Add tasks
    tm.Add("Learn Go structs", "Complete the structs module", PriorityHigh)
    tm.Add("Buy groceries", "Milk, eggs, bread", PriorityMedium)
    tm.Add("Walk the dog", "30 minute walk in the park", PriorityLow)
    tm.Add("Write blog post", "Go tutorial for beginners", PriorityHigh)

    fmt.Println("=== All Tasks ===")
    tm.ListAll()

    // Complete a task
    tm.Complete(1)
    tm.Complete(3)

    fmt.Println("\n=== After Completing Tasks ===")
    tm.ListAll()

    // Filter by priority
    fmt.Println("\n=== High Priority ===")
    for _, task := range tm.ListByPriority(PriorityHigh) {
        fmt.Println(task)
    }

    // Stats
    total, done, pending := tm.Stats()
    fmt.Printf("\n=== Stats ===\nTotal: %d | Done: %d | Pending: %d\n",
        total, done, pending)

    // Delete
    tm.Delete(2)
    fmt.Println("\n=== After Deleting Task #2 ===")
    tm.ListAll()

    _ = strings.Repeat("", 0) // keep import for the module
}

