package main

import "fmt"

type Node struct {
    Data int
    Next *Node
}

type LinkedList struct {
    Head *Node
}

func (l *LinkedList) InsertAtBeginning(data int) {
    newNode := &Node{Data: data}
    newNode.Next = l.Head
    l.Head = newNode
}

func (l *LinkedList) InsertAtEnd(data int) {
    newNode := &Node{Data: data}
    if l.Head == nil {
        l.Head = newNode
        return
    }
    current := l.Head
    for current.Next != nil {
        current = current.Next
    }
    current.Next = newNode
}

func (l *LinkedList) Search(target int) bool {
    current := l.Head
    for current != nil {
        if current.Data == target {
            return true
        }
        current = current.Next
    }
    return false
}

func (l *LinkedList) Print() {
    current := l.Head
    for current != nil {
        fmt.Printf("%d -> ", current.Data)
        current = current.Next
    }
    fmt.Println("nil")
}

func main() {
    list := LinkedList{}

    list.InsertAtEnd(10)
    list.InsertAtEnd(20)
    list.InsertAtEnd(30)
    list.InsertAtBeginning(5)

    list.Print()  // 5 -> 10 -> 20 -> 30 -> nil

    fmt.Println("Search 20:", list.Search(20))  // true
    fmt.Println("Search 99:", list.Search(99))  // false
}

