package main

import "fmt"

// Speaker defines a behavior: anything that can Speak
type Speaker interface {
    Speak() string
}

// Dog is a type with a Speak method
type Dog struct {
    Name string
}

func (d Dog) Speak() string {
    return d.Name + " says: Woof!"
}

// Cat is a different type, also with a Speak method
type Cat struct {
    Name string
}

func (c Cat) Speak() string {
    return c.Name + " says: Meow!"
}

// greet accepts ANY Speaker — it doesn't care if it's a Dog or Cat
func greet(s Speaker) {
    fmt.Println(s.Speak())
}

func main() {
