package main

import "fmt"

// Small, focused interfaces
type Namer interface {
    Name() string
}

type Saver interface {
    Save() error
}

type Deleter interface {
    Delete() error
}

// Composed interfaces
type Persistable interface {
    Saver
    Deleter
}

type Entity interface {
    Namer
    Persistable  // Namer + Saver + Deleter = 3 methods
}

// User satisfies Entity (it has Name, Save, and Delete)
type User struct {
