package main

import "fmt"

type Logger interface {
    Log(msg string)
}

type FileLogger struct {
    Path string
}

func (f *FileLogger) Log(msg string) {
    fmt.Println("Logging to", f.Path, ":", msg)
}

func main() {
    // Case 1: Truly nil interface
    var log1 Logger
    fmt.Println("log1 == nil?", log1 == nil) // true

    // Case 2: Interface holding a nil pointer (THE TRAP!)
    var fileLog *FileLogger  // nil pointer to FileLogger
    var log2 Logger = fileLog
    fmt.Println("log2 == nil?", log2 == nil) // FALSE! 😱

    // Why? Because log2 has type info (*FileLogger) even though
    // the actual pointer value is nil.

    fmt.Printf("log2 type: %T, value: %v\n", log2, log2)
    // log2 type: *main.FileLogger, value: <nil>
}

sections.content:
This pattern causes bugs constantly:

```go
func getLogger() Logger {
    var f *FileLogger  // nil pointer
    // ... some logic that might not set f ...
    return f  // Returns interface with type *FileLogger but nil value
}

func main() {
    log := getLogger()
    if log != nil {  // This is TRUE (the interface isn't nil!)
        log.Log("hello")  // PANIC: nil pointer dereference
    }
}
```

The fix: return `nil` explicitly, not a typed nil pointer:

```go
func getLogger() Logger {
    var f *FileLogger
    if f == nil {
        return nil  // Returns a truly nil interface
    }
    return f
}
```

