package main

import "fmt"

// Step 1: Define the interface for what we depend on
type EmailSender interface {
    Send(to, subject, body string) error
}

// Step 2: The real implementation (used in production)
type SMTPSender struct {
    Host string
    Port int
}

func (s SMTPSender) Send(to, subject, body string) error {
    // In real code, this would connect to an SMTP server
    fmt.Printf("REAL: Sending email to %s via %s:%d\n", to, s.Host, s.Port)
    return nil
}

// Step 3: The fake implementation (used in tests)
type FakeSender struct {
    SentEmails []struct {
        To, Subject, Body string
    }
}

func (f *FakeSender) Send(to, subject, body string) error {
    f.SentEmails = append(f.SentEmails, struct {
        To, Subject, Body string
    }{to, subject, body})
    return nil
}

// Step 4: Our business logic accepts the INTERFACE, not a concrete type
type UserService struct {
    Mailer EmailSender
}

func (u UserService) Register(email, name string) error {
    // ... create user in database ...
    // Send welcome email
    return u.Mailer.Send(
        email,
        "Welcome!",
        fmt.Sprintf("Hi %s, welcome to our app!", name),
    )
}

func main() {
    // In production:
    prodService := UserService{
        Mailer: SMTPSender{Host: "smtp.example.com", Port: 587},
    }
    prodService.Register("alice@example.com", "Alice")

    // In tests:
    fake := &FakeSender{}
    testService := UserService{Mailer: fake}
    testService.Register("bob@test.com", "Bob")

    // Verify the email was 'sent'
    fmt.Printf("\nTest: %d emails sent\n", len(fake.SentEmails))
    fmt.Printf("Test: First email to: %s\n", fake.SentEmails[0].To)
    fmt.Printf("Test: Subject: %s\n", fake.SentEmails[0].Subject)
}

// user_service_test.go
package main

import "testing"

func TestRegisterSendsWelcomeEmail(t *testing.T) {
    // Arrange
    fake := &FakeSender{}
    service := UserService{Mailer: fake}

    // Act
    err := service.Register("test@example.com", "Charlie")

    // Assert
    if err != nil {
        t.Fatalf("unexpected error: %v", err)
    }

    if len(fake.SentEmails) != 1 {
        t.Fatalf("expected 1 email, got %d", len(fake.SentEmails))
    }

    email := fake.SentEmails[0]
    if email.To != "test@example.com" {
        t.Errorf("expected email to test@example.com, got %s", email.To)
    }
    if email.Subject != "Welcome!" {
        t.Errorf("expected subject 'Welcome!', got %s", email.Subject)
    }
}

