import "fmt"

// Custom error type with extra context
type ValidationError struct {
    Field   string
    Message string
}

// Satisfy the error interface
func (v ValidationError) Error() string {
    return fmt.Sprintf("validation failed on field '%s': %s", v.Field, v.Message)
}

// Another custom error
type NotFoundError struct {
    Resource string
    ID       int
}

func (n NotFoundError) Error() string {
    return fmt.Sprintf("%s with ID %d not found", n.Resource, n.ID)
}

func findUser(id int) (string, error) {
    if id <= 0 {
        return "", ValidationError{Field: "id", Message: "must be positive"}
    }
    if id > 100 {
        return "", NotFoundError{Resource: "User", ID: id}
    }
    return "Alice", nil
}

func main() {
    _, err := findUser(-1)
    if err != nil {
        fmt.Println("Error:", err)
        // You can type-assert to get extra context:
        if ve, ok := err.(ValidationError); ok {
            fmt.Println("  Bad field:", ve.Field)
        }
    }

    _, err = findUser(999)
    if err != nil {
        fmt.Println("Error:", err)
        if nfe, ok := err.(NotFoundError); ok {
            fmt.Println("  Missing:", nfe.Resource, nfe.ID)
        }
    }
}

