package main

import (
    "fmt"
    "math"
    "sort"
    "strings"
)

// ========== INTERFACES ==========

type Shape interface {
    Area() float64
    Perimeter() float64
    fmt.Stringer  // Embeds Stringer — all shapes must have String()
}

// ========== SHAPES ==========

type Circle struct {
    Radius float64
}

func (c Circle) Area() float64      { return math.Pi * c.Radius * c.Radius }
func (c Circle) Perimeter() float64  { return 2 * math.Pi * c.Radius }
func (c Circle) String() string      { return fmt.Sprintf("Circle(r=%.1f)", c.Radius) }

type Rectangle struct {
    Width, Height float64
}

func (r Rectangle) Area() float64      { return r.Width * r.Height }
func (r Rectangle) Perimeter() float64  { return 2 * (r.Width + r.Height) }
func (r Rectangle) String() string {
    return fmt.Sprintf("Rectangle(%.1f×%.1f)", r.Width, r.Height)
}

type Triangle struct {
    A, B, C float64  // Side lengths
}

func (t Triangle) Area() float64 {
    // Heron's formula
    s := t.Perimeter() / 2
    return math.Sqrt(s * (s - t.A) * (s - t.B) * (s - t.C))
}
func (t Triangle) Perimeter() float64 { return t.A + t.B + t.C }
func (t Triangle) String() string {
    return fmt.Sprintf("Triangle(%.1f, %.1f, %.1f)", t.A, t.B, t.C)
}

// ========== UTILITY FUNCTIONS ==========

func printShapeInfo(s Shape) {
    fmt.Printf("  %s\n", s)
    fmt.Printf("    Area:      %.2f\n", s.Area())
    fmt.Printf("    Perimeter: %.2f\n", s.Perimeter())
}

func totalArea(shapes []Shape) float64 {
    total := 0.0
    for _, s := range shapes {
        total += s.Area()
    }
    return total
}

func largestShape(shapes []Shape) Shape {
    if len(shapes) == 0 {
        return nil
    }
    largest := shapes[0]
    for _, s := range shapes[1:] {
        if s.Area() > largest.Area() {
            largest = s
        }
    }
    return largest
}

// Sort shapes by area
type ByArea []Shape
func (a ByArea) Len() int           { return len(a) }
func (a ByArea) Swap(i, j int)      { a[i], a[j] = a[j], a[i] }
func (a ByArea) Less(i, j int) bool { return a[i].Area() < a[j].Area() }

func main() {
    shapes := []Shape{
        Circle{Radius: 5},
        Rectangle{Width: 10, Height: 4},
        Triangle{A: 3, B: 4, C: 5},
        Circle{Radius: 2},
        Rectangle{Width: 7, Height: 7},
    }

    fmt.Println("=== All Shapes ===")
    for _, s := range shapes {
        printShapeInfo(s)
    }

    fmt.Printf("\n=== Statistics ===\n")
    fmt.Printf("Total area: %.2f\n", totalArea(shapes))
    fmt.Printf("Largest shape: %s (area: %.2f)\n",
        largestShape(shapes), largestShape(shapes).Area())

    fmt.Println("\n=== Sorted by Area ===")
    sort.Sort(ByArea(shapes))
    for _, s := range shapes {
        fmt.Printf("  %s → area: %.2f\n", s, s.Area())
    }

    // Type switch to count each kind
    fmt.Println("\n=== Shape Counts ===")
    counts := make(map[string]int)
    for _, s := range shapes {
        switch s.(type) {
        case Circle:
            counts["circles"]++
        case Rectangle:
            counts["rectangles"]++
        case Triangle:
            counts["triangles"]++
        }
    }
    parts := []string{}
    for kind, count := range counts {
        parts = append(parts, fmt.Sprintf("%d %s", count, kind))
    }
    fmt.Println(strings.Join(parts, ", "))
}

