package main

import (
	"context"
	"fmt"
	"net/http"
	"sync"
	"time"
)

// Result holds the check result for a single URL
type Result struct {
	URL      string
	Status   string
	Duration time.Duration
	Error    error
}

// checkURL checks if a URL is reachable
func checkURL(ctx context.Context, url string) Result {
	start := time.Now()

	req, err := http.NewRequestWithContext(ctx, "GET", url, nil)
	if err != nil {
		return Result{URL: url, Status: "ERROR", Duration: time.Since(start), Error: err}
	}

	resp, err := http.DefaultClient.Do(req)
	if err != nil {
		return Result{URL: url, Status: "DOWN", Duration: time.Since(start), Error: err}
	}
	defer resp.Body.Close()

	return Result{
		URL:      url,
		Status:   fmt.Sprintf("UP (%d)", resp.StatusCode),
		Duration: time.Since(start),
	}
}

// worker processes URLs from the jobs channel
func worker(ctx context.Context, id int, jobs <-chan string, results chan<- Result, wg *sync.WaitGroup) {
	defer wg.Done()
	for url := range jobs {
		fmt.Printf("Worker %d: checking %s\n", id, url)
		result := checkURL(ctx, url)
		results <- result
	}
}

func main() {
	urls := []string{
		"https://www.google.com",
		"https://www.github.com",
		"https://www.golang.org",
		"https://www.example.com",
		"https://httpstat.us/500",
		"https://thiswebsitedoesnotexist12345.com",
		"https://www.wikipedia.org",
		"https://www.stackoverflow.com",
	}

	// Create context with 10-second overall timeout
	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	// Create channels
	jobs := make(chan string, len(urls))
	results := make(chan Result, len(urls))

	// Start worker pool (3 concurrent workers)
	var wg sync.WaitGroup
	numWorkers := 3
	for w := 1; w <= numWorkers; w++ {
		wg.Add(1)
		go worker(ctx, w, jobs, results, &wg)
	}

	// Send all URLs as jobs
	for _, url := range urls {
		jobs <- url
	}
	close(jobs)

	// Close results channel when all workers are done
	go func() {
		wg.Wait()
		close(results)
	}()

	// Collect and display results
	fmt.Println("\n===== RESULTS =====")
	var upCount, downCount int
	for result := range results {
		if result.Error != nil {
			fmt.Printf("❌ %-45s %s (%v) - %v\n", result.URL, result.Status, result.Duration.Round(time.Millisecond), result.Error)
			downCount++
		} else {
			fmt.Printf("✅ %-45s %s (%v)\n", result.URL, result.Status, result.Duration.Round(time.Millisecond))
			upCount++
		}
	}
	fmt.Printf("\n📊 Summary: %d up, %d down, %d total\n", upCount, downCount, upCount+downCount)
}

