)

func main() {
    // os.Stdout is an *os.File that implements io.Writer
    // fmt.Println actually writes to os.Stdout behind the scenes!

    // These two lines do the same thing:
    fmt.Println("Hello via fmt.Println")
    fmt.Fprintln(os.Stdout, "Hello via fmt.Fprintln to Stdout")

    // You can also write raw bytes directly
    os.Stdout.Write([]byte("Hello via raw Write\n"))
}

