package main

import (
    "bufio"
    "fmt"
    "os"
    "strings"
)

func main() {
    // Create a sample file
    content := `Go is a programming language.
Go was designed at Google.
Go is great for building servers.
Go has built-in concurrency support.
Go compiles to native machine code.`
    os.WriteFile("about_go.txt", []byte(content), 0644)

    file, err := os.Open("about_go.txt")
    if err != nil {
        fmt.Println("Error:", err)
        return
    }
    defer file.Close()

    totalLines := 0
    totalWords := 0
    wordCount := make(map[string]int)

    scanner := bufio.NewScanner(file)
    for scanner.Scan() {
        line := scanner.Text()
        totalLines++

        words := strings.Fields(line) // Split line into words
        totalWords += len(words)

        for _, word := range words {
            lower := strings.ToLower(word)
            // Remove trailing punctuation
            lower = strings.TrimRight(lower, ".,!?;:")
            wordCount[lower]++
        }
    }

    fmt.Printf("Total lines: %d\n", totalLines)
    fmt.Printf("Total words: %d\n", totalWords)
    fmt.Println("\nWord frequencies:")
    for word, count := range wordCount {
        if count > 1 {
            fmt.Printf("  '%s' appears %d times\n", word, count)
        }
    }

    os.Remove("about_go.txt")
}

