package main

import (
    "encoding/json"
    "fmt"
)

type Product struct {
    Name     string  `json:"name"`
    Price    float64 `json:"price"`
    InStock  bool    `json:"in_stock"`
    Category string  `json:"category"`
}

func main() {
    // Imagine this JSON came from an API response
    jsonString := `{
        "name": "Mechanical Keyboard",
        "price": 149.99,
        "in_stock": true,
        "category": "electronics"
    }`

    // Create a variable to hold the decoded data
    var product Product

    // json.Unmarshal converts JSON bytes → Go struct
    err := json.Unmarshal([]byte(jsonString), &product)
    if err != nil {
        fmt.Println("Error:", err)
        return
    }

    // Now we can use the data as a normal Go struct!
    fmt.Printf("Product: %s\n", product.Name)
    fmt.Printf("Price: $%.2f\n", product.Price)
    fmt.Printf("In stock: %t\n", product.InStock)
    fmt.Printf("Category: %s\n", product.Category)

    // We can do calculations, comparisons, etc.
    if product.InStock && product.Price < 200 {
        fmt.Println("\n✅ Great deal! Buy it!")
