package main

import (
    "encoding/json"
    "fmt"
    "net/http"
    "os"
    "strconv"
    "strings"
    "sync"
    "time"
)

// ==================== Data Model ====================

type Todo struct {
    ID        int       `json:"id"`
    Title     string    `json:"title"`
    Completed bool      `json:"completed"`
    CreatedAt time.Time `json:"created_at"`
}

// ==================== Data Store ====================

type TodoStore struct {
    mu     sync.Mutex // Protects concurrent access
    todos  []Todo
    nextID int
    file   string
}

func NewTodoStore(filename string) *TodoStore {
    store := &TodoStore{
        file:   filename,
        nextID: 1,
    }
    store.load() // Load existing todos from file
    return store
}

func (s *TodoStore) load() {
    data, err := os.ReadFile(s.file)
    if err != nil {
        return // File doesn't exist yet, start empty
    }
    json.Unmarshal(data, &s.todos)
    // Set nextID to one more than the highest existing ID
    for _, t := range s.todos {
        if t.ID >= s.nextID {
            s.nextID = t.ID + 1
        }
    }
}

func (s *TodoStore) save() error {
    data, err := json.MarshalIndent(s.todos, "", "  ")
    if err != nil {
        return err
    }
    return os.WriteFile(s.file, data, 0644)
}

func (s *TodoStore) All() []Todo {
    s.mu.Lock()
    defer s.mu.Unlock()
    result := make([]Todo, len(s.todos))
    copy(result, s.todos)
    return result
}

func (s *TodoStore) Add(title string) Todo {
    s.mu.Lock()
    defer s.mu.Unlock()
    todo := Todo{
        ID:        s.nextID,
        Title:     title,
        Completed: false,
        CreatedAt: time.Now(),
    }
    s.nextID++
    s.todos = append(s.todos, todo)
    s.save()
    return todo
}

func (s *TodoStore) Toggle(id int) (Todo, bool) {
    s.mu.Lock()
    defer s.mu.Unlock()
    for i, t := range s.todos {
        if t.ID == id {
            s.todos[i].Completed = !s.todos[i].Completed
            s.save()
            return s.todos[i], true
        }
    }
    return Todo{}, false
}

func (s *TodoStore) Delete(id int) bool {
    s.mu.Lock()
    defer s.mu.Unlock()
    for i, t := range s.todos {
        if t.ID == id {
            s.todos = append(s.todos[:i], s.todos[i+1:]...)
            s.save()
            return true
        }
    }
    return false
}

// ==================== HTTP Handlers ====================

var store *TodoStore

func todosHandler(w http.ResponseWriter, r *http.Request) {
    w.Header().Set("Content-Type", "application/json")

    switch r.Method {
    case http.MethodGet:
        todos := store.All()
        json.NewEncoder(w).Encode(todos)

    case http.MethodPost:
        var input struct {
            Title string `json:"title"`
        }
        if err := json.NewDecoder(r.Body).Decode(&input); err != nil {
            w.WriteHeader(http.StatusBadRequest)
            json.NewEncoder(w).Encode(map[string]string{"error": "Invalid JSON"})
            return
        }
        if strings.TrimSpace(input.Title) == "" {
            w.WriteHeader(http.StatusBadRequest)
            json.NewEncoder(w).Encode(map[string]string{"error": "Title is required"})
            return
        }
        todo := store.Add(input.Title)
        w.WriteHeader(http.StatusCreated)
        json.NewEncoder(w).Encode(todo)

    default:
        w.WriteHeader(http.StatusMethodNotAllowed)
    }
}

func todoByIDHandler(w http.ResponseWriter, r *http.Request) {
    w.Header().Set("Content-Type", "application/json")

    // Extract ID from URL path: /todos/123
    idStr := strings.TrimPrefix(r.URL.Path, "/todos/")
    id, err := strconv.Atoi(idStr)
    if err != nil {
        w.WriteHeader(http.StatusBadRequest)
        json.NewEncoder(w).Encode(map[string]string{"error": "Invalid ID"})
        return
    }

    switch r.Method {
    case http.MethodPut:
        todo, found := store.Toggle(id)
        if !found {
            w.WriteHeader(http.StatusNotFound)
            json.NewEncoder(w).Encode(map[string]string{"error": "Todo not found"})
            return
        }
        json.NewEncoder(w).Encode(todo)

    case http.MethodDelete:
        if !store.Delete(id) {
            w.WriteHeader(http.StatusNotFound)
            json.NewEncoder(w).Encode(map[string]string{"error": "Todo not found"})
            return
        }
        json.NewEncoder(w).Encode(map[string]string{"message": "Deleted"})

    default:
        w.WriteHeader(http.StatusMethodNotAllowed)
    }
}

// ==================== Main ====================

func main() {
    store = NewTodoStore("todos.json")

    http.HandleFunc("/todos", todosHandler)
    http.HandleFunc("/todos/", todoByIDHandler)

    port := os.Getenv("PORT")
    if port == "" {
        port = "8080"
    }

    fmt.Printf("Todo API server running on http://localhost:%s\n", port)
    fmt.Println("Endpoints:")
    fmt.Println("  GET    /todos       - List all todos")
    fmt.Println("  POST   /todos       - Create a todo")
    fmt.Println("  PUT    /todos/{id}  - Toggle completion")
    fmt.Println("  DELETE /todos/{id}  - Delete a todo")

    http.ListenAndServe(":"+port, nil)
}

