package task

import (
	"errors"
	"time"
)

// Common errors returned by TaskStore operations
var (
	ErrTaskNotFound = errors.New("task not found")
	ErrEmptyTitle   = errors.New("task title cannot be empty")
)

// TaskStore manages a collection of tasks
type TaskStore struct {
	tasks  []Task
	nextID int
}

// NewTaskStore creates and returns a new, empty TaskStore
func NewTaskStore() *TaskStore {
	return &TaskStore{
		tasks:  make([]Task, 0),
		nextID: 1,
	}
}

// Add creates a new task and returns it
func (s *TaskStore) Add(title string, priority Priority) (Task, error) {
	// Validate input
	if title == "" {
		return Task{}, ErrEmptyTitle
	}

	// Create the task
	t := Task{
		ID:        s.nextID,
		Title:     title,
		Completed: false,
		Priority:  priority,
		CreatedAt: time.Now(),
	}

	// Add to our collection and increment ID
	s.tasks = append(s.tasks, t)
	s.nextID++

	return t, nil
}

// List returns all tasks (a copy, so callers can't modify our internal slice)
func (s *TaskStore) List() []Task {
	result := make([]Task, len(s.tasks))
	copy(result, s.tasks)
	return result
}

// Get finds a task by ID
func (s *TaskStore) Get(id int) (Task, error) {
	for _, t := range s.tasks {
		if t.ID == id {
			return t, nil
		}
	}
	return Task{}, ErrTaskNotFound
}

// findIndex returns the index of a task with the given ID, or -1 if not found
func (s *TaskStore) findIndex(id int) int {
	for i, t := range s.tasks {
		if t.ID == id {
			return i
		}
	}
	return -1
}

// Len returns the number of tasks
func (s *TaskStore) Len() int {
	return len(s.tasks)
}

