// Complete marks a task as done by its ID
func (s *TaskStore) Complete(id int) error {
	index := s.findIndex(id)
	if index == -1 {
		return ErrTaskNotFound
	}

	if s.tasks[index].Completed {
		return fmt.Errorf("task #%d is already completed", id)
	}

	s.tasks[index].Completed = true
	s.tasks[index].CompletedAt = time.Now()

	return nil
}

sections.content:
You might be tempted to write:
```go
for _, t := range s.tasks {
    if t.ID == id {
        t.Completed = true  // BUG! This modifies a copy!
    }
}
```
This doesn't work because `range` gives you a **copy** of each element. You must use the index: `s.tasks[i].Completed = true`. This is one of Go's most common gotchas.

sections.code:
// Delete removes a task by its ID
func (s *TaskStore) Delete(id int) error {
	index := s.findIndex(id)
	if index == -1 {
		return ErrTaskNotFound
	}

	// Remove element at index by slicing
	// This preserves the order of remaining elements
	s.tasks = append(s.tasks[:index], s.tasks[index+1:]...)

	return nil
}

// Pending returns only incomplete tasks
func (s *TaskStore) Pending() []Task {
	var result []Task
	for _, t := range s.tasks {
		if !t.Completed {
			result = append(result, t)
		}
	}
	return result
}

// CompletedTasks returns only finished tasks
func (s *TaskStore) CompletedTasks() []Task {
	var result []Task
	for _, t := range s.tasks {
		if t.Completed {
			result = append(result, t)
		}
	}
	return result
}

// ByPriority returns tasks filtered by priority level
func (s *TaskStore) ByPriority(p Priority) []Task {
	var result []Task
	for _, t := range s.tasks {
		if t.Priority == p {
			result = append(result, t)
		}
	}
	return result
}

