package task

import (
	"encoding/json"
	"errors"
	"os"
)

// storeData is the structure we save to JSON
// It includes not just tasks but also metadata like the next ID
type storeData struct {
	Tasks  []Task `json:"tasks"`
	NextID int    `json:"next_id"`
}

// SaveToFile writes all tasks to a JSON file
func (s *TaskStore) SaveToFile(filename string) error {
	data := storeData{
		Tasks:  s.tasks,
		NextID: s.nextID,
	}

	// Marshal with indentation for readability
	jsonBytes, err := json.MarshalIndent(data, "", "  ")
	if err != nil {
		return fmt.Errorf("failed to marshal tasks: %w", err)
	}

	// Write to file with permissions: owner can read/write
	err = os.WriteFile(filename, jsonBytes, 0644)
	if err != nil {
		return fmt.Errorf("failed to write file %s: %w", filename, err)
	}

	return nil
}

// LoadFromFile reads tasks from a JSON file
func (s *TaskStore) LoadFromFile(filename string) error {
	// Read the file
	jsonBytes, err := os.ReadFile(filename)
	if err != nil {
		// If the file doesn't exist, that's OK — it's a fresh start
		if errors.Is(err, os.ErrNotExist) {
			return nil
		}
		return fmt.Errorf("failed to read file %s: %w", filename, err)
	}

	// Parse the JSON
	var data storeData
	err = json.Unmarshal(jsonBytes, &data)
	if err != nil {
		return fmt.Errorf("failed to parse JSON from %s: %w", filename, err)
	}

	// Restore the store's state
	s.tasks = data.Tasks
	s.nextID = data.NextID

	return nil
}

