package main

import (
	"fmt"
	"log"
	"os"
	"strconv"
	"strings"

	"github.com/yourname/taskmanager/task"
)

const dataFile = "tasks.json"

func main() {
	// Load existing tasks
	store, err := task.FileBackedStore(dataFile)
	if err != nil {
		log.Fatalf("Error loading tasks: %v\n", err)
	}

	// Check if user provided a command
	if len(os.Args) < 2 {
		printUsage()
		os.Exit(1)
	}

	// Route to the right command
	command := strings.ToLower(os.Args[1])
	switch command {
	case "add":
		handleAdd(store, os.Args[2:])
	case "list":
		handleList(store, os.Args[2:])
	case "complete", "done":
		handleComplete(store, os.Args[2:])
	case "delete", "rm":
		handleDelete(store, os.Args[2:])
	case "help":
		printUsage()
	default:
		fmt.Fprintf(os.Stderr, "Unknown command: %s\n\n", command)
		printUsage()
		os.Exit(1)
	}

	// Save after every operation
	if err := store.SaveToFile(dataFile); err != nil {
		log.Fatalf("Error saving tasks: %v\n", err)
	}
}

func printUsage() {
	fmt.Println(`Task Manager — Manage your to-do list from the terminal

Usage:
  taskmanager <command> [arguments]

Commands:
  add <title> [--priority low|medium|high]   Add a new task
  list [--all|--pending|--done]              List tasks
  complete <id>                              Mark a task as done
  delete <id>                                Remove a task
  help                                       Show this help message

Examples:
  taskmanager add "Buy groceries" --priority high
  taskmanager list --pending
  taskmanager complete 1
  taskmanager delete 3`)
}

func handleAdd(store *task.TaskStore, args []string) {
	if len(args) == 0 {
		fmt.Fprintln(os.Stderr, "Error: Please provide a task title")
		fmt.Fprintln(os.Stderr, "Usage: taskmanager add \"Your task title\"")
		os.Exit(1)
	}

	title := args[0]
	priority := task.PriorityMedium // default

	// Check for --priority flag
	for i, arg := range args {
		if arg == "--priority" && i+1 < len(args) {
			switch strings.ToLower(args[i+1]) {
			case "low":
				priority = task.PriorityLow
			case "medium":
				priority = task.PriorityMedium
			case "high":
				priority = task.PriorityHigh
			default:
				fmt.Fprintf(os.Stderr, "Unknown priority: %s (use low, medium, high)\n", args[i+1])
				os.Exit(1)
			}
		}
	}

	newTask, err := store.Add(title, priority)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

