func TestAdd(t *testing.T) {
	s := NewTaskStore()

	// Test successful add
	task, err := s.Add("Test task", PriorityHigh)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if task.ID != 1 {
		t.Errorf("expected ID 1, got %d", task.ID)
	}
	if task.Title != "Test task" {
		t.Errorf("expected title 'Test task', got '%s'", task.Title)
	}
	if task.Priority != PriorityHigh {
		t.Errorf("expected priority HIGH, got %v", task.Priority)
	}
	if task.Completed {
		t.Error("new task should not be completed")
	}
	if s.Len() != 1 {
		t.Errorf("expected store length 1, got %d", s.Len())
	}

	// Test empty title
	_, err = s.Add("", PriorityLow)
	if !errors.Is(err, ErrEmptyTitle) {
		t.Errorf("expected ErrEmptyTitle, got %v", err)
	}

	// Ensure failed add didn't change store
	if s.Len() != 1 {
		t.Errorf("failed add should not change store length, got %d", s.Len())
	}
}

func TestComplete(t *testing.T) {
	tests := []struct {
		name      string
		id        int
		wantErr   error
		setup     func(s *TaskStore) // optional setup before test
	}{
		{
			name:    "complete existing task",
			id:      1,
			wantErr: nil,
		},
		{
			name:    "complete non-existent task",
			id:      99,
			wantErr: ErrTaskNotFound,
		},
		{
			name:    "complete already completed task",
			id:      1,
			wantErr: nil, // We'll check for a non-nil error
			setup: func(s *TaskStore) {
				s.Complete(1) // Complete it first
			},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			s := newTestStore()
			if tt.setup != nil {
				tt.setup(s)
			}

			err := s.Complete(tt.id)

			if tt.name == "complete already completed task" {
				if err == nil {
					t.Error("expected error when completing already completed task")
				}
				return
			}

			if tt.wantErr != nil {
				if !errors.Is(err, tt.wantErr) {
					t.Errorf("expected error %v, got %v", tt.wantErr, err)
				}
				return
			}

			if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}

			// Verify the task is actually completed
			task, _ := s.Get(tt.id)
			if !task.Completed {
				t.Error("task should be completed after Complete()")
			}
			if task.CompletedAt.IsZero() {
				t.Error("CompletedAt should be set")
			}
		})
	}
}

func TestSaveAndLoad(t *testing.T) {
	// Create a temporary file for testing
	tmpFile := "test_tasks_temp.json"
	defer os.Remove(tmpFile) // Clean up after test

	// Create and populate a store
	original := newTestStore()
	original.Complete(2)

	// Save it
	err := original.SaveToFile(tmpFile)
	if err != nil {
		t.Fatalf("SaveToFile failed: %v", err)
	}

	// Load into a fresh store
	loaded := NewTaskStore()
	err = loaded.LoadFromFile(tmpFile)
	if err != nil {
		t.Fatalf("LoadFromFile failed: %v", err)
	}

	// Verify the data matches
	if loaded.Len() != original.Len() {
		t.Errorf("expected %d tasks, got %d", original.Len(), loaded.Len())
	}

	// Check specific task data survived the round-trip
	task2, err := loaded.Get(2)
	if err != nil {
		t.Fatalf("couldn't find task 2: %v", err)
	}
	if !task2.Completed {
		t.Error("task 2 should still be completed after save/load")
	}
	if task2.Title != "Task Two" {
		t.Errorf("expected title 'Task Two', got '%s'", task2.Title)
	}
}

func TestLoadNonExistentFile(t *testing.T) {
	s := NewTaskStore()
	err := s.LoadFromFile("this_file_does_not_exist.json")
	if err != nil {
		t.Errorf("loading non-existent file should not error, got: %v", err)
	}
	if s.Len() != 0 {
		t.Errorf("store should be empty, got %d tasks", s.Len())
	}
}

