import "strings"

const maxTitleLength = 200

// Add creates a new task with validated input
func (s *TaskStore) Add(title string, priority Priority) (Task, error) {
	// Trim whitespace
	title = strings.TrimSpace(title)

	// Validate
	if title == "" {
		return Task{}, ErrEmptyTitle
	}

	if len(title) > maxTitleLength {
		return Task{}, fmt.Errorf("task title too long (%d chars, max %d)", len(title), maxTitleLength)
	}

	if priority < PriorityLow || priority > PriorityHigh {
		return Task{}, fmt.Errorf("invalid priority: %d (must be 0-2)", priority)
	}

	// Create the task (same as before)
	t := Task{
		ID:        s.nextID,
		Title:     title,
		Completed: false,
		Priority:  priority,
		CreatedAt: time.Now(),
	}

	s.tasks = append(s.tasks, t)
	s.nextID++

	return t, nil
}

// LoadFromFile with recovery for corrupted files
func (s *TaskStore) LoadFromFile(filename string) error {
	jsonBytes, err := os.ReadFile(filename)
	if err != nil {
		if errors.Is(err, os.ErrNotExist) {
			return nil // First run — no file yet
		}
		return fmt.Errorf("failed to read %s: %w", filename, err)
	}

	// Empty file is OK — treat as fresh start
	if len(jsonBytes) == 0 {
		return nil
	}

	var data storeData
	err = json.Unmarshal(jsonBytes, &data)
	if err != nil {
		// JSON is corrupted — don't crash, provide a helpful message
		return fmt.Errorf(
			"the data file %s appears to be corrupted: %w\n"+
				"Tip: Check if the file was manually edited. "+
				"You can delete it to start fresh, or restore from a backup",
			filename, err,
		)
	}

	// Validate loaded data
	if data.NextID < 1 {
		data.NextID = 1
	}
	if data.Tasks == nil {
		data.Tasks = make([]Task, 0)
	}

	s.tasks = data.Tasks
	s.nextID = data.NextID

	return nil
}

