package task

import (
	"sync"
	"time"
)

// TaskStore manages a collection of tasks (now thread-safe)
type TaskStore struct {
	mu     sync.Mutex
	tasks  []Task
	nextID int
}

func (s *TaskStore) Add(title string, priority Priority) (Task, error) {
	s.mu.Lock()
	defer s.mu.Unlock()

	title = strings.TrimSpace(title)
	if title == "" {
		return Task{}, ErrEmptyTitle
	}

	t := Task{
		ID:        s.nextID,
		Title:     title,
		Completed: false,
		Priority:  priority,
		CreatedAt: time.Now(),
	}

	s.tasks = append(s.tasks, t)
	s.nextID++

	return t, nil
}

func (s *TaskStore) Complete(id int) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	index := s.findIndex(id)
	if index == -1 {
		return ErrTaskNotFound
	}

	if s.tasks[index].Completed {
		return fmt.Errorf("task #%d is already completed", id)
	}

	s.tasks[index].Completed = true
	s.tasks[index].CompletedAt = time.Now()
	return nil
}

func (s *TaskStore) List() []Task {
	s.mu.Lock()
	defer s.mu.Unlock()

	result := make([]Task, len(s.tasks))
	copy(result, s.tasks)
	return result
}

func (s *TaskStore) Delete(id int) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	index := s.findIndex(id)
	if index == -1 {
		return ErrTaskNotFound
	}

	s.tasks = append(s.tasks[:index], s.tasks[index+1:]...)
	return nil
}

package task

import (
	"context"
	"log"
	"time"
)

// StartAutoSave begins saving the store to a file at regular intervals.
// It runs in a background goroutine and stops when the context is cancelled.
func (s *TaskStore) StartAutoSave(ctx context.Context, filename string, interval time.Duration) {
	go func() {
		ticker := time.NewTicker(interval)
		defer ticker.Stop()

		for {
			select {
			case <-ticker.C:
				// Time to save!
				if err := s.SaveToFile(filename); err != nil {
					log.Printf("Auto-save failed: %v", err)
				}
			case <-ctx.Done():
				// Context cancelled — do one final save and exit
				if err := s.SaveToFile(filename); err != nil {
					log.Printf("Final save failed: %v", err)
				}
				return
			}
		}
	}()
}

func main() {
	store, err := task.FileBackedStore(dataFile)
	if err != nil {
		log.Fatalf("Error loading tasks: %v\n", err)
	}

	// Start auto-save every 30 seconds
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel() // This triggers the final save when main() exits
	store.StartAutoSave(ctx, dataFile, 30*time.Second)

	// ... rest of CLI handling ...

	// The deferred cancel() runs here, stopping auto-save gracefully
}

